css:
.fn { display: flex; flex-direction: column; gap: 6px; width: 100%; }
.fn-stage { display: flex; align-items: center; gap: 12px; opacity: 0; transform: translateX(-12px); transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1); }
.fn-stage.visible { opacity: 1; transform: translateX(0); }
.fn-bar { height: 38px; border-radius: 6px; width: 0; transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1); flex-shrink: 0; }
.fn-info { min-width: 90px; }
.fn-name { font-size: 13px; font-weight: 600; color: var(--text); display: block; }
.fn-sub { font-size: 11px; color: var(--text-muted); }
.fn-rate { font-size: 12px; font-weight: 600; margin-left: auto; padding: 2px 10px; border-radius: 12px; white-space: nowrap; }
.fn-drop { font-size: 10px; color: var(--text-muted); text-align: center; padding: 2px 0; opacity: 0; transition: opacity 0.4s; }
.fn-drop.visible { opacity: 1; }

.hm { width: 100%; }
.hm-grid { display: flex; flex-direction: column; gap: 3px; }
.hm-row { display: grid; grid-template-columns: 44px repeat(7, 1fr); gap: 3px; }
.hm-label { font-size: 10px; color: var(--text-muted); display: flex; align-items: center; }
.hm-head { font-size: 10px; color: var(--text-muted); text-align: center; font-weight: 600; text-transform: uppercase; }
.hm-cell { aspect-ratio: 1.6; border-radius: 3px; opacity: 0; transition: opacity 0.3s; cursor: pointer; position: relative; }
.hm-cell.visible { opacity: 1; }
.hm-cell:hover { outline: 1px solid var(--text-muted); }
.hm-cell:hover::after { content: attr(data-val); position: absolute; top: -20px; left: 50%; transform: translateX(-50%); font-size: 9px; color: var(--text); background: var(--bg); padding: 1px 5px; border-radius: 3px; border: 1px solid var(--border); white-space: nowrap; z-index: 1; }
.hm-scale { display: flex; align-items: center; gap: 6px; margin-top: 8px; justify-content: flex-end; }
.hm-scale-bar { width: 80px; height: 8px; border-radius: 4px; background: linear-gradient(90deg, rgba(234,88,12,0.05), rgba(234,88,12,0.9)); }
.hm-scale span { font-size: 9px; color: var(--text-muted); }

.rd { width: 100%; display: flex; flex-direction: column; align-items: center; }
.rd-chart { position: relative; }
.rd-axis { stroke: var(--border); stroke-width: 1; }
.rd-ring { fill: none; stroke: var(--border); stroke-width: 0.5; stroke-dasharray: 4 4; }
.rd-poly { fill-opacity: 0; stroke-width: 2; stroke-dasharray: 500; stroke-dashoffset: 500; transition: stroke-dashoffset 1.2s cubic-bezier(0.4, 0, 0.2, 1), fill-opacity 0.6s 0.8s; }
.rd-poly.visible { stroke-dashoffset: 0; fill-opacity: 0.12; }
.rd-poly.cur { stroke: #ea580c; fill: #ea580c; }
.rd-poly.prev { stroke: #3b82f6; fill: #3b82f6; }
.rd-dot { r: 3; fill: var(--bg); stroke-width: 2; opacity: 0; transition: opacity 0.3s 1s; }
.rd-dot.visible { opacity: 1; }
.rd-dot.cur { stroke: #ea580c; }
.rd-dot.prev { stroke: #3b82f6; }
.rd-lbl { font-size: 10px; fill: var(--text-muted); text-anchor: middle; }
.rd-legend { display: flex; gap: 20px; justify-content: center; margin-top: 16px; font-size: 12px; color: var(--text-muted); }
.rd-legend-dot { width: 10px; height: 10px; border-radius: 50%; display: inline-block; margin-right: 6px; vertical-align: middle; }

.wf { width: 100%; }
.wf-chart { display: flex; align-items: flex-end; gap: 4px; height: 240px; padding-bottom: 24px; position: relative; }
.wf-chart::before { content: ''; position: absolute; left: 0; right: 0; bottom: 24px; height: 1px; background: var(--border); }
.wf-col { flex: 1; position: relative; height: 100%; display: flex; flex-direction: column; justify-content: flex-end; align-items: center; }
.wf-block { width: 65%; border-radius: 3px; position: relative; opacity: 0; transform: scaleY(0); transform-origin: bottom; transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1); }
.wf-block.visible { opacity: 1; transform: scaleY(1); }
.wf-block.add { background: #22c55e; }
.wf-block.sub { background: #ef4444; transform-origin: top; }
.wf-block.total { background: var(--link); }
.wf-val { font-size: 10px; font-weight: 600; color: var(--text); text-align: center; margin-bottom: 4px; opacity: 0; transition: opacity 0.3s 0.4s; white-space: nowrap; }
.wf-val.visible { opacity: 1; }
.wf-lbl { font-size: 9px; color: var(--text-muted); text-align: center; white-space: nowrap; position: absolute; bottom: -18px; }
.wf-connector { position: absolute; right: -4px; width: 8px; border-top: 1px dashed var(--text-muted); opacity: 0.4; }

.gg-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; width: 100%; max-width: 360px; margin: 0 auto; }
.gg-item { display: flex; flex-direction: column; align-items: center; gap: 6px; opacity: 0; transform: scale(0.9); transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1); }
.gg-item.visible { opacity: 1; transform: scale(1); }
.gg-track { fill: none; stroke: var(--border); stroke-width: 10; stroke-linecap: round; }
.gg-fill { fill: none; stroke-width: 10; stroke-linecap: round; transition: stroke-dashoffset 1.2s cubic-bezier(0.4, 0, 0.2, 1); }
.gg-val { font-size: 18px; font-weight: 700; text-anchor: middle; fill: var(--text); }
.gg-lbl { font-size: 12px; color: var(--text-muted); text-align: center; font-weight: 600; }
.gg-sub { font-size: 10px; color: var(--text-muted); text-align: center; }

slides.script:
var stages = container.querySelectorAll('.fn-stage');
var drops = container.querySelectorAll('.fn-drop');
stages.forEach(function(s, i) {
  setTimeout(function() {
    s.classList.add('visible');
    var bar = s.querySelector('.fn-bar');
    bar.style.width = bar.getAttribute('data-w');
    if (i > 0 && drops[i - 1]) {
      drops[i - 1].textContent = drops[i - 1].getAttribute('data-text');
      drops[i - 1].classList.add('visible');
    }
  }, 200 + i * 180);
});

var cells = container.querySelectorAll('.hm-cell');
cells.forEach(function(c, i) {
  setTimeout(function() {
    c.classList.add('visible');
  }, 50 + i * 20);
});

var polys = container.querySelectorAll('.rd-poly');
var dots = container.querySelectorAll('.rd-dot');
polys.forEach(function(p, i) {
  setTimeout(function() { p.classList.add('visible'); }, 200 + i * 300);
});
dots.forEach(function(d, i) {
  setTimeout(function() { d.classList.add('visible'); }, 400);
});

var blocks = container.querySelectorAll('.wf-block');
var vals = container.querySelectorAll('.wf-val');
blocks.forEach(function(b, i) {
  var h = b.style.height;
  b.style.height = '0';
  setTimeout(function() {
    b.style.height = h;
    b.classList.add('visible');
  }, 150 + i * 120);
});
vals.forEach(function(v, i) {
  setTimeout(function() {
    v.textContent = v.getAttribute('data-v');
    v.classList.add('visible');
  }, 300 + i * 120);
});

var items = container.querySelectorAll('.gg-item');
items.forEach(function(item, i) {
  setTimeout(function() {
    item.classList.add('visible');
    var fill = item.querySelector('.gg-fill');
    var pct = parseFloat(fill.getAttribute('data-pct')) / 100;
    var totalLen = 141.4;
    fill.style.strokeDashoffset = totalLen * (1 - pct);
    var valEl = item.querySelector('.gg-val');
    valEl.textContent = valEl.getAttribute('data-v');
  }, 200 + i * 150);
});
